#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
map<char,int> mp1,mp2;int ans=0;string a,b;
int main(void){
	cin>>a>>b;
	int max_l=max(a.length(),b.length());
	for(int i=0;i<a.length();++i)++mp1[a[i]];
	for(int i=0;i<b.length();++i)++mp2[b[i]];
	for(int i=97;i<123;++i){
		char c=(char)(i);
		ans+=min(mp1[c],mp2[c]);
	}cout<<ans;
	return false;	
}
